// HITL request builder. The LLM (unknown-agent's request_write_action tool)
// passes ONE raw string that is a JSON object; accept that (under .query, as a
// string or already an object) or a directly-structured item. Validate +
// whitelist, then emit SQL-safe (single-quotes doubled) values for the INSERT.
// This does NOT execute anything — it only prepares a pending row.
const raw = ($input.first() && $input.first().json) || {};
const tryParse = (s) => { try { return JSON.parse(s); } catch (e) { return null; } };
let req = {};
if (raw.query !== undefined) {
  if (typeof raw.query === 'string') { req = tryParse(raw.query) || {}; }
  else if (raw.query && typeof raw.query === 'object') { req = raw.query; }
}
if (!req.action_type && (raw.action_type || raw.target_system)) { req = raw; }
const errOut = (msg) => [{ json: { ok: false, error: msg } }];
let action_type = String(req.action_type || '').trim().toLowerCase();
const target_system = String(req.target_system || '').trim().toLowerCase();
const target_id = String(req.target_id || '').trim();
let human_summary = String(req.human_summary || '').trim();
const normalized_payload = (req.normalized_payload && typeof req.normalized_payload === 'object') ? req.normalized_payload : {};
if (['n8n', 'github'].indexOf(target_system) < 0) { return errOut('target_system חייב להיות n8n או github'); }
if (target_system === 'n8n' && ['activate', 'deactivate'].indexOf(action_type) < 0) { return errOut('עבור n8n, action_type חייב להיות activate או deactivate'); }
if (target_system === 'n8n' && !target_id) { return errOut('חסר target_id (מזהה ה-workflow ב-n8n)'); }
if (target_system === 'github' && !target_id) { return errOut('חסר target_id (שם קובץ ה-workflow ב-GitHub, למשל deploy.yml)'); }
if (target_system === 'github' && !action_type) { action_type = 'dispatch'; }
if (!human_summary) { human_summary = action_type + ' ' + target_system + (target_id ? (' ' + target_id) : ''); }
const esc = (s) => String(s).replace(/'/g, "''");
const idempotency_key = Date.now() + '-' + Math.random().toString(36).slice(2, 12);
return [{ json: { ok: true, action_type, target_system, target_id, human_summary, human_summary_sql: esc(human_summary), target_id_sql: esc(target_id), normalized_payload_str: esc(JSON.stringify(normalized_payload)), idempotency_key } }];

// button-send-outcome-trace: mint a per-send tool_call_id + a SQL-safe input summary
// for the approval-button send (mirrors postgres-named-queries' Mint Trace). esc()
// doubles single quotes so arbitrary LLM input can't break the INSERT; onError on the
// trace writers keeps the bot's reply safe even if a trace write fails.
const p = ($('Parse Request').first() && $('Parse Request').first().json) || {};
const ins = ($input.first() && $input.first().json) || {};
const esc = (s) => String(s).replace(/'/g, "''");
const toolCallId = Date.now() + '-' + Math.random().toString(36).slice(2, 12);
let summary = '';
try { summary = JSON.stringify({ action_type: p.action_type || '', target_system: p.target_system || '', target_id: p.target_id || '', human_summary: p.human_summary || '', pending_id: ins.id || null }); } catch (e) { summary = '{}'; }
if (summary.length > 2000) { summary = summary.slice(0, 2000); }
return [{ json: { tool_call_id: toolCallId, input_summary_sql: esc(summary), pending_id: ins.id || null } }];

// button-send-outcome-trace: normalize the failure reason from EITHER the send node's
// error port ($json.error) OR the guard-false branch (200 OK but no message_id), and
// esc() it SQL-safe. Keeps the failed-trace UPDATE one clean node fed by both sources.
const j = ($input.first() && $input.first().json) || {};
const esc = (s) => String(s).replace(/'/g, "''");
let reason;
if (j.error) { reason = (typeof j.error === 'object') ? (j.error.message || JSON.stringify(j.error)) : ('' + j.error); }
else { reason = 'send reported ok but no message_id (possible false-success)'; }
reason = String(reason).slice(0, 500);
return [{ json: { error_message_sql: esc(reason) } }];
